from flask import Flask, request
from prometheus_client import Counter, generate_latest

app = Flask(__name__)

# Initialize a counter metric with labels for user_id, session_id, and full_request_path
http_requests_total = Counter(
    'http_requests_total',
    'Total HTTP requests by user and path',
    ['user_id', 'session_id', 'full_request_path']
)

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.route('/', defaults={'path': ''})
@app.route('/<path:path>')
def catch_all(path):
    # Extract user_id, session_id from headers or cookies
    user_id = request.headers.get('X-User-ID', 'unknown')
    session_id = request.headers.get('X-Session-ID', 'unknown')

    # Increment the metric with labels for user_id, session_id, and full_request_path
    http_requests_total.labels(user_id, session_id, path).inc()

    return f'Request received: {path}'

